import Chip from '@mui/material/Chip';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';

export default function BlacklistPage() {
  const columns = [
    { key: 'rut', label: 'RUT' },
    { key: 'plate', label: 'Patente' },
    { key: 'reason', label: 'Motivo' },
    {
      key: 'is_active',
      label: 'Estado',
      render: (row) => <Chip size="small" label={row.is_active ? 'Activo' : 'Inactivo'} color={row.is_active ? 'error' : 'default'} />
    }
  ];

  const fields = [
    { name: 'rut', label: 'RUT' },
    { name: 'plate', label: 'Patente' },
    { name: 'reason', label: 'Motivo', fullWidth: true },
    { name: 'is_active', label: 'Activo', type: 'checkbox', defaultValue: true }
  ];

  return <CrudResourceModule title="Lista Negra" path="/access/blacklist/" columns={columns} fields={fields} defaultOrdering="-created_at" />;
}

